$("._tab").click(function() {
    let parentBlock = $(this).parents("._tabs-parent")
    let tabId = $(this).attr("data-tab")
    $(parentBlock).find("._tab").removeClass("_active")
    $(this).addClass("_active")
    $(parentBlock).find(".tab-content").removeClass("_active")
    $(parentBlock).find(`.${tabId}`).addClass("_active")
})

$(".qa-card__show").click(function() {
    $(this).parents(".qa-card").toggleClass("_active")
    $(this).siblings(".qa-card__hidden").slideToggle()
})

$(".catalog-spoiler__show").click(function() {
    $(this).parents(".catalog-spoiler").toggleClass("_open")
    $(this).siblings(".catalog-spoiler__hidden").slideToggle()
})

let breadsLength = $(".breadcrumbs__item").length
if (breadsLength > 2) {
    $(".breadcrumbs").addClass("breadcrumbs--collapse")
}
$(".breadcrumbs__btn").click(function() {
    $(".breadcrumbs").removeClass("breadcrumbs--collapse")
})

$("._toggle-more").click(function() {
    $(this).parents("._toggle-more-parent").toggleClass("_show-all")
})

$(".cart-btn,.favourite-btn").click(function() {
    $(this).toggleClass("_added")
})

$("[data-copy]").click(function () {
    let text = $(this).attr("data-copy")
    let $tmp = $("<textarea>");
    $("body").append($tmp);
    $tmp.val(text).select();
    document.execCommand("copy");
    $tmp.remove();
    $(this).addClass("_copied")
})

$(".scroll-up").click(function() {
    $("body,html").scrollTop(0);
})
$(window).scroll(function() {
    if ($(window).scrollTop() > 100) {
        $(".scroll-up").addClass("scroll-up--active")
    } else {
        $(".scroll-up").removeClass("scroll-up--active")
    }
})

$("._toggle-menu").click(function () {
    $(".m-page").toggleClass("_open-menu")
    $("body").toggleClass("fixed-body")
})

$(".header-action__toggle").click(function () {
    $(".header-action").toggleClass("_open")
})

$(document).mouseup( function(e){
    let div = $( ".header-action" );
    if ( !div.is(e.target)
        && div.has(e.target).length === 0 ) {
        if($(div).hasClass("_open")){
            $(div).removeClass("_open")
        }
    }
});

$("._toggle-catalog").click(function () {
    $(".m-page").toggleClass("_open-catalog")
    if($(".m-page").hasClass("_open-menu")){
        $(".m-page").removeClass("_open-menu")
        return
    }
    $("body").toggleClass("fixed-body")
})

$("._back-to-menu").click(function () {
    $(".m-page").removeClass("_open-catalog")
    $(".m-page").addClass("_open-menu")
    $(".header-catalog").removeClass("_open-sub-catalog")
    $(".menu-item").removeClass("_open")
})

fixHeader()
$(window).scroll(function() {
    fixHeader()
})

function fixHeader() {
    let headerTop = $(".header-top").innerHeight()

    if ($(window).scrollTop() > headerTop) {
        $(".m-page").addClass("_fix-header")
    } else {
        $(".m-page").removeClass("_fix-header")
    }
}

$(window).resize(function() {
    if (window.innerWidth < 993) {
        $(".header-search input").attr("placeholder", "Поиск товаров")
    } else {
        $(".header-search input").attr("placeholder", "Введите название или артикул товара")
    }
})

if (window.innerWidth < 993) {
    $(".header-bottom .header-search input").attr("placeholder", "Поиск товаров")
} else {
    $(".header-bottom .header-search input").attr("placeholder", "Введите название или артикул товара")
}

$(".menu-item__back").click(function () {
    $(".header-catalog").removeClass("_open-sub-catalog")
    $(this).parents(".menu-item").removeClass("_open")
})

$(".menu-item__show").click(function () {
    $(".menu-item").removeClass("_open")
    $(".header-catalog").addClass("_open-sub-catalog")
    $(this).parents(".menu-item").addClass("_open")
})

$(".menu-item__show").mouseover(function () {
    if (window.innerWidth < 993) {
        return
    }
    $(".menu-item").removeClass("_open")
    $(this).parents(".menu-item").addClass("_open")
})

function Sliders() {
    let SlidersArray = []

    let sliders = document.querySelectorAll(".slider")
    sliders.forEach((slider,index) => {
        slider.setAttribute("data-slider-id",index)

        SlidersArray[index] = new Swiper(`.slider[data-slider-id="${index}"] .swiper-container`, {
            slidesPerView: "auto",
            spaceBetween: 0,
            watchSlidesProgress: true,
            preventClicks :true,
            a11y: false,
            observer: true,
            observeParents: true,
            observeSlideChildren: true,

            navigation: {
                nextEl: `.slider[data-slider-id="${index}"] .swiper-button-next`,
                prevEl: `.slider[data-slider-id="${index}"] .swiper-button-prev`,
            },
            pagination: {
                el: `.slider[data-slider-id="${index}"] .swiper-pagination`,
                type: 'bullets',
                clickable: true,
            },
        })
    })
}

function gallery() {
    let SlidersArray = []

    let sliders = document.querySelectorAll(".gallery")
    sliders.forEach((slider,index) => {
        slider.setAttribute("data-slider-id",index)
        let gallery = {
            mySwiper: {},
            mySwiper2: {}
        }

        gallery.mySwiper = new Swiper(`.gallery[data-slider-id="${index}"] .mySwiper`, {
            spaceBetween: 0,
            slidesPerView: "auto",
            freeMode: true,
            watchSlidesProgress: true,
        });
        gallery.mySwiper2 = new Swiper(`.gallery[data-slider-id="${index}"] .mySwiper2`, {
            spaceBetween: 0,
            navigation: {
                nextEl: `.gallery[data-slider-id="${index}"] .swiper-button-next`,
                prevEl: `.gallery[data-slider-id="${index}"] .swiper-button-prev`,
            },
            thumbs: {
                swiper:  gallery.mySwiper,
            },
        });

        SlidersArray[index] = gallery
    })

}


Sliders()
gallery()

